import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { RefreshCw, Download, Clock, FileText, AlertCircle } from 'lucide-react';
import { useToast } from '@/components/ui/use-toast';
import { format } from 'date-fns';

interface DataSource {
  name: string;
  source: string;
  lastScan: string | null;
  documentCount: number;
  chunkCount: number;
  status: 'active' | 'updating' | 'error';
}

interface IngestionProgress {
  status: string;
  total: number;
  completed: number;
  failed: number;
  skipped: number;
}

export const DataSourcesPanel: React.FC = () => {
  const [sources, setSources] = useState<DataSource[]>([]);
  const [loading, setLoading] = useState(false);
  const [ingesting, setIngesting] = useState(false);
  const [taskId, setTaskId] = useState<string | null>(null);
  const [progress, setProgress] = useState<IngestionProgress | null>(null);
  const { toast } = useToast();

  useEffect(() => {
    fetchDataSources();
  }, []);

  useEffect(() => {
    if (taskId) {
      const interval = setInterval(() => {
        checkIngestionProgress(taskId);
      }, 2000);
      return () => clearInterval(interval);
    }
  }, [taskId]);

  const fetchDataSources = async () => {
    try {
      const response = await fetch('/api/dashboard/data-sources', {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      const data = await response.json();
      setSources(data.sources);
    } catch (error) {
      toast({
        title: 'Error',
        description: 'Failed to fetch data sources',
        variant: 'destructive'
      });
    }
  };

  const handleIngestAML = async () => {
    setIngesting(true);
    try {
      const response = await fetch('/api/dashboard/ingest-aml', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });

      if (!response.ok) throw new Error('Failed to start ingestion');

      const data = await response.json();
      setTaskId(data.task_id);

      toast({
        title: 'Ingestion Started',
        description: 'AML document ingestion is in progress'
      });
    } catch (error) {
      toast({
        title: 'Error',
        description: 'Failed to start AML ingestion',
        variant: 'destructive'
      });
      setIngesting(false);
    }
  };

  const checkIngestionProgress = async (id: string) => {
    try {
      const response = await fetch(`/api/dashboard/ingest-aml/${id}`, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      const data = await response.json();
      setProgress(data);

      if (data.status === 'completed') {
        setIngesting(false);
        setTaskId(null);
        setProgress(null);
        fetchDataSources();

        toast({
          title: 'Ingestion Complete',
          description: `Processed ${data.completed} documents successfully`
        });
      }
    } catch (error) {
      console.error('Failed to check progress:', error);
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center justify-between">
          <span>Data Sources</span>
          <Button
            size="sm"
            variant="outline"
            onClick={fetchDataSources}
            disabled={loading}
          >
            <RefreshCw className="h-4 w-4 mr-2" />
            Refresh
          </Button>
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          {sources.map((source) => (
            <div key={source.source} className="border rounded-lg p-4">
              <div className="flex items-center justify-between mb-2">
                <h3 className="font-semibold">{source.name}</h3>
                <Badge variant={source.status === 'active' ? 'default' : 'secondary'}>
                  {source.status}
                </Badge>
              </div>

              <div className="grid grid-cols-3 gap-4 text-sm text-gray-600">
                <div className="flex items-center">
                  <Clock className="h-4 w-4 mr-1" />
                  Last scan: {source.lastScan ? format(new Date(source.lastScan), 'MMM d, HH:mm') : 'Never'}
                </div>
                <div className="flex items-center">
                  <FileText className="h-4 w-4 mr-1" />
                  {source.documentCount} documents
                </div>
                <div className="flex items-center">
                  <FileText className="h-4 w-4 mr-1" />
                  {source.chunkCount} chunks
                </div>
              </div>

              {source.source === 'aml.gov.sa' && (
                <div className="mt-3">
                  <Button
                    size="sm"
                    onClick={handleIngestAML}
                    disabled={ingesting}
                  >
                    <Download className="h-4 w-4 mr-2" />
                    {ingesting ? 'Ingesting...' : 'Ingest AML Documents'}
                  </Button>

                  {progress && (
                    <div className="mt-2 p-2 bg-gray-50 rounded text-sm">
                      <div>Status: {progress.status}</div>
                      <div>Progress: {progress.completed + progress.skipped}/{progress.total}</div>
                      {progress.failed > 0 && (
                        <div className="text-red-600">
                          <AlertCircle className="h-4 w-4 inline mr-1" />
                          {progress.failed} failed
                        </div>
                      )}
                    </div>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  );
};
