from sqlalchemy import func, and_
from datetime import datetime, timedelta

@router.get("/api/dashboard/data-sources")
async def get_data_sources_stats(
    current_user: dict = Depends(get_current_user),
    db: Session = Depends(get_db)
):
    """Get statistics for all data sources"""

    sources_data = []

    # CMA Statistics
    cma_docs = db.query(func.count(Document.id)).filter(
        Document.source == 'cma.gov.sa'
    ).scalar() or 0

    cma_chunks = db.query(func.count(Chunk.id)).join(Document).filter(
        Document.source == 'cma.gov.sa'
    ).scalar() or 0

    # Get last CMA scan from alerts or scraping logs
    last_cma_scan = db.query(func.max(Alert.created_at)).filter(
        Alert.source == 'cma.gov.sa'
    ).scalar()

    sources_data.append({
        'name': 'Capital Market Authority (CMA)',
        'source': 'cma.gov.sa',
        'lastScan': last_cma_scan.isoformat() if last_cma_scan else None,
        'documentCount': cma_docs,
        'chunkCount': cma_chunks,
        'status': 'active'
    })

    # AML Statistics
    aml_docs = db.query(func.count(Document.id)).filter(
        Document.source == 'aml.gov.sa'
    ).scalar() or 0

    aml_chunks = db.query(func.count(Chunk.id)).join(Document).filter(
        Document.source == 'aml.gov.sa'
    ).scalar() or 0

    # Get last AML ingestion time
    last_aml_ingest = db.query(func.max(Document.created_at)).filter(
        Document.source == 'aml.gov.sa'
    ).scalar()

    # Check if ingestion is in progress
    aml_status = 'active'
    for task_id, progress in ingestion_progress.items():
        if progress['status'] != 'completed':
            aml_status = 'updating'
            break

    sources_data.append({
        'name': 'Anti-Money Laundering Authority (AML)',
        'source': 'aml.gov.sa',
        'lastScan': last_aml_ingest.isoformat() if last_aml_ingest else None,
        'documentCount': aml_docs,
        'chunkCount': aml_chunks,
        'status': aml_status
    })

    # Additional metrics
    total_documents = cma_docs + aml_docs
    total_chunks = cma_chunks + aml_chunks

    # Get recent activity (last 7 days)
    recent_date = datetime.utcnow() - timedelta(days=7)
    recent_docs = db.query(func.count(Document.id)).filter(
        Document.created_at >= recent_date
    ).scalar() or 0

    return {
        'sources': sources_data,
        'summary': {
            'totalDocuments': total_documents,
            'totalChunks': total_chunks,
            'recentDocuments': recent_docs
        }
    }

@router.get("/api/dashboard/source-details/{source}")
async def get_source_details(
    source: str,
    current_user: dict = Depends(get_current_user),
    db: Session = Depends(get_db)
):
    """Get detailed information about a specific source"""

    if source not in ['cma.gov.sa', 'aml.gov.sa']:
        raise HTTPException(status_code=400, detail="Invalid source")

    # Get documents by category
    categories = db.query(
        Document.doc_type,
        func.count(Document.id).label('count')
    ).filter(
        Document.source == source
    ).group_by(Document.doc_type).all()

    # Get recent documents
    recent_docs = db.query(Document).filter(
        Document.source == source
    ).order_by(Document.created_at.desc()).limit(10).all()

    return {
        'source': source,
        'categories': [
            {'type': cat.doc_type, 'count': cat.count}
            for cat in categories
        ],
        'recentDocuments': [
            {
                'id': doc.id,
                'title': doc.title,
                'type': doc.doc_type,
                'createdAt': doc.created_at.isoformat()
            }
            for doc in recent_docs
        ]
    }
